import{_ as t,o as a,c as o,aq as r}from"./chunks/framework.DLfWLF6u.js";const d=JSON.parse('{"title":"The 5 AI Tools You Need After ChatGPT (that do real work)","description":"","frontmatter":{},"headers":[],"relativePath":"AI/JeffSu/the-5-ai-tools-you-need-after-chatgpt-(that-do-real-work).md","filePath":"AI/JeffSu/the-5-ai-tools-you-need-after-chatgpt-(that-do-real-work).md","lastUpdated":0}'),i={name:"AI/JeffSu/the-5-ai-tools-you-need-after-chatgpt-(that-do-real-work).md"};function n(s,e,l,h,c,g){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="the-5-ai-tools-you-need-after-chatgpt-that-do-real-work" tabindex="-1">The 5 AI Tools You Need After ChatGPT (that do real work) <a class="header-anchor" href="#the-5-ai-tools-you-need-after-chatgpt-that-do-real-work" aria-label="Permalink to “The 5 AI Tools You Need After ChatGPT (that do real work)”">​</a></h1><h2 id="english-summary" tabindex="-1">English Summary <a class="header-anchor" href="#english-summary" aria-label="Permalink to “English Summary”">​</a></h2><ul><li><p><strong>Google Workspace (Gemini Integration)</strong>: The core strength lies in its native integration rather than just the model. It can search and synthesize data across Gmail, Docs, Drive, and Calendar in a single query, making it ideal for summarizing complex projects with fragmented information [01:21].</p></li><li><p><strong>Notion AI</strong>: Functions as a &quot;knowledge work agent&quot; that can take action within a workspace. Unlike standard chatbots, it can create, populate, and reorganize documents or databases from scratch based on existing templates and relations [03:14].</p></li><li><p><strong>Whisper Flow</strong>: Specialized in high-accuracy voice-to-text transcription. It reduces the friction of typing, allowing users to provide much richer context and &quot;brain dump&quot; ideas that the AI then cleans up with 95% accuracy [05:23].</p></li><li><p><strong>Midjourney</strong>: Aimed at power users who want complete creative control. It uses a manual &quot;syntax&quot; mode (similar to manual camera settings) to provide the highest precision over image outputs, though it has a steeper learning curve [06:48].</p></li><li><p><strong>Google Nano Banana Pro</strong>: Excels at natural language precision editing and iteration. It allows users to modify specific parts of an image (like changing text or colors) using plain English without having to regenerate the entire image from scratch [08:36].</p></li><li><p><strong>GPT Image Model (DALL-E Integration)</strong>: Its &quot;superpower&quot; is memory and consistency. It is more reliable than competitors at maintaining the same characters or visual elements across a sequence of multiple generated images [10:30].</p></li><li><p><strong>Google Flow</strong>: Specialized in animating transitions between images. It can take two static images (e.g., a wireframe and a finished product) and generate the motion frames to create a smooth transformation video [12:27].</p></li></ul><h2 id="视频总结-chinese" tabindex="-1">视频总结 (Chinese) <a class="header-anchor" href="#视频总结-chinese" aria-label="Permalink to “视频总结 (Chinese)”">​</a></h2><ul><li><p><strong>Google Workspace (Gemini 集成)</strong>: 核心优势在于原生集成。它可以在单个查询中搜索并综合 Gmail、文档、云端硬盘和日历中的数据，非常适合总结信息分散的复杂项目 [01:21]。</p></li><li><p><strong>Notion AI</strong>: 作为“知识工作代理”，它可以在工作区内执行操作。与标准聊天机器人不同，它可以根据现有模板和关联，从头开始创建、填充和重组文档或数据库 [03:14]。</p></li><li><p><strong>Whisper Flow</strong>: 专注于高精度的语音转文字。它减少了打字的阻力，允许用户提供更丰富的上下文，AI 能以 95% 的准确率清理这些“脑力激荡”出的内容 [05:23]。</p></li><li><p><strong>Midjourney</strong>: 面向追求完全创意控制的高级用户。它使用手动的“语法”模式（类似于相机的手动设置），对图像输出提供最高的精确度，尽管学习曲线较陡 [06:48]。</p></li><li><p><strong>Google Nano Banana Pro</strong>: 擅长自然语言精密编辑和迭代。它允许用户使用简单的英语修改图像的特定部分（如更改文本或颜色），而无需重新生成整张图像 [08:36]。</p></li><li><p><strong>GPT 图像模型 (DALL-E 集成)</strong>: 其“超能力”是记忆和一致性。在跨多个生成的图像序列中保持相同角色或视觉元素方面，它比竞争对手更可靠 [10:30]。</p></li><li><p><strong>Google Flow</strong>: 专门用于生成图像之间的动画过渡。它可以获取两张静态图像（例如线框图和成品图），并生成运动帧以创建平滑的转换视频 [12:27]。</p></li></ul><hr><p><strong>Source</strong>: <a href="https://www.youtube.com/watch?v=aH9ctWaxGgQ" target="_blank" rel="noreferrer">Jeff Su</a></p>',7)])])}const u=t(i,[["render",n]]);export{d as __pageData,u as default};
